var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 저와 닮은 꼴이랍니다, 노엘.","JPN":"あなたは私と似ているんですよ、ノエル。","ENG":"You are like me, Noelle.","TWN":"你和我很像呢，洛艾兒。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_18"},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"스스로가 진정 원하는 것을 알지 못한 채, 방황하며 타인을 모방할 뿐이죠.","JPN":"自らが本当に望むことを知らないまま、彷徨いながら他人を模倣するだけです。","ENG":"You don't know what you truly want, and imitate others while wandering around.","TWN":"在不知道自己真正想要什麼的情況下，只是漫無目的地徘徊並模仿他人。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_19"},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 증거로 당신의 이름과 모습은 이곳에서 오래전에 죽어버린 가련한 소녀의 것을 훔친 것에 불과해요.","JPN":"その証拠として、あなたの名前と姿はずいぶん前にここで死んでしまった可哀そうな少女のものを盗んだに過ぎません。","ENG":"Proof of that is how you stole the name and appearance of a little girl that died long ago.","TWN":"作為證據，你的名字和樣貌不過是竊取自這裡很久以前死去的可憐少女的東西。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_20"},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 가족과 이웃……. 그리고 이 마을의 모든 존재가 세계를 만드는 법칙에 의해 창조된 허구니까요.","JPN":"あなたの家族と隣人……そして、この村のすべての存在が世界を作る法則によって創造された虚構ですから。","ENG":"Your family and your neighbors... and everyone else in this village are all fiction created by the law of creating a world.","TWN":"你的家人和鄰居……以及這個村莊的所有存在，都是由創造世界的法則所虛構的。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_21"},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 힘은 양날의 검이랍니다. 주위를 둘러보세요.","JPN":"その力は両刃の剣です。周りを見渡してください。","ENG":"That power is a double-edged sword. Just take a look around you.","TWN":"那力量是柄雙刃劍。環顧四周吧。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_22"},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신, 그리고 당신이 창조해낸 것들이 정말로 인간이라고 할 수 있나요?","JPN":"あなたとあなたが創造したものは本当に人間だと言えますか？","ENG":"Can you really call yourself and the beings you created humans?","TWN":"你，還有你創造的那些東西，真的能稱之為人類嗎？"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_23"},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"받아들이세요. 당신은 무엇 하나 자신의 것이 없습니다.","JPN":"受け入れてください。あなたには何一つ自分のものがありません。","ENG":"Accept it. None of this is yours.","TWN":"接受吧。你一無所有。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_24"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 땅에 내려온 당신이 처음으로 행했던 것은 늑대를 찾는 일.","JPN":"この地に降りてきたあなたが最初に行ったことは、オオカミを探すこと。","ENG":"The first thing you did when you came down here is find the Wolf.","TWN":"你降臨這片土地後做的第一件事就是尋找那只狼。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_25"},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그것조차도 당신 스스로의 의지가 아닌, 세피로트 나무가 당신에게 부여한 의무였겠죠.","JPN":"それさえもあなたの意志ではなく、セフィロトの樹があなたに与えた義務だったのでしょう。","ENG":"Even that wasn't your own decision but a duty given to you by the Tree of Sephiroth.","TWN":"那也不是你自己的意願，而是生命樹賦予你的義務吧。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_26"},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 말이 틀린가요, 노엘 라이트?","JPN":"私の話が間違っていますか、ノエル・ライト？","ENG":"Am I wrong, Noelle Wright?","TWN":"我說錯了嗎，洛艾兒·萊特？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_27"},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니, 세피라의 화신!","JPN":"いいえ、セフィラの化身！","ENG":"Or should I say, the personification of Sephira!","TWN":"不，塞菲拉的化身！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_28"},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"うっ……！！","ENG":"Kgh...!!","TWN":"咳……！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엄마, 아빠, 치즈 그리고 마을 사람들…….","JPN":"お母さん、お父さん、チーズ、そして村のみんなが……","ENG":"Mom, Dad, Cheese, and the other villagers...","TWN":"媽媽，爸爸，起司，還有村民們……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신 말대로 모든 게 허구였다고 하더라도…….","JPN":"あなたの言うとおり、すべてが虚構だったとしても……","ENG":"Even if they are all fiction like you say, they are...","TWN":"就算一切如你所說都是虛構的……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배와의 만남이 제 의지가 아니었다고 하더라도…….","JPN":"ミナ先輩との出会いが自分の意志ではなかったとしても……","ENG":"Or even if it wasn't my will to go see Mina...","TWN":"即使與米娜前輩的相遇並非我的意願……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저에겐…… 모두가 소중한 인연이라고 생각해요.","JPN":"私にとって……みんな大事な絆だと思うんです。","ENG":"They are all... still precious people to me.","TWN":"對我來說……每一個都是珍貴的緣分。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그러니까……!","JPN":"だから……！","ENG":"So...!","TWN":"所以……！"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"무슨 일이 있어도, 당신 뜻대로 내버려두진 않겠어……!","JPN":"何があっても、あなたの思いどおりにはさせない……！","ENG":"Whatever happens, I won't let you have your way...!","TWN":"不管發生什麼事，我都不會任由你隨心所欲……!"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요.","JPN":"いいでしょう。","ENG":"Very well.","TWN":"很好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_29"},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금부터 당신으로 하여금, 저를 따르는 것 이외의 모든 선택지를 제거하겠습니다.","JPN":"今からあなたには私に従う以外のすべての選択肢を除外します。","ENG":"From this point onward, I will remove all other options beside your following me.","TWN":"從現在開始，我將排除你除了跟隨我之外的所有選擇。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_30"},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 제가 원하는 모든 것을 이루기 위해서, 기꺼이 악역을 받아들이겠어요.","JPN":"私は自分が求めるすべてのことを成し遂げるために、喜んで悪役を引き受けます。","ENG":"I will gladly step in as the villain if it means I get what I want.","TWN":"為了實現我想要的一切，我甘願接受成為反派。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_31"},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기쁘게, 당신의 모든 것을 짓밟겠어요.","JPN":"喜んで、あなたのすべてを踏みにじりましょう。","ENG":"I will be more than happy to trample on everything you have.","TWN":"我很高興，能夠摧毀你的一切。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_32"},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……세피라의 화신.","JPN":"……セフィラの化身。","ENG":"…Personification of Sephira.","TWN":"……塞菲拉的化身。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_33"}]`);export{e as default};